              <span style={{width:34,height:34,borderRadius:10,flexShrink:0,background:(dDone||dd.today)?LIME:IC2,color:(dDone||dd.today)?LIMED:MU,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:F.ios,fontWeight:700,fontSize:11}}>{dDone?<Ico n="check" s={16} c={LIMED}/>:dd.d}</span>
