              <Sub style={{fontSize:11,marginTop:4}}>{r.location||"—"} · {r.modality} · {r.gender==="F"?<Ico n="female" s={12}/>:r.gender==="Mixed"?<Ico n="mixed" s={12}/>:<Ico n="male" s={12}/>}</Sub>
