                  <div style={{flex:1,minWidth:0}}><div style={{fontFamily:F.ios,fontSize:13,color:C.text,fontWeight:600}}>{r.coachName}</div><Sub style={{fontSize:11}}>Toca para ver contacto</Sub></div>
